class _UniffiFfiConverterString:
    @staticmethod
    def check_lower(value):
        if not isinstance(value, str):
            raise TypeError("argument must be str, not {}".format(type(value).__name__))
        return value

    @staticmethod
    def read(buf):
        size = buf.read_i32()
        if size < 0:
            raise InternalError("Unexpected negative string length")
        utf8_bytes = buf.read(size)
        return utf8_bytes.decode("utf-8")

    @staticmethod
    def write(value, buf):
        utf8_bytes = value.encode("utf-8")
        buf.write_i32(len(utf8_bytes))
        buf.write(utf8_bytes)

    @staticmethod
    def lift(buf):
        with buf.consume_with_stream() as stream:
            return stream.read(stream.remaining()).decode("utf-8")

    @staticmethod
    def lower(value):
        with _UniffiRustBuffer.alloc_with_builder() as builder:
            builder.write(value.encode("utf-8"))
            return builder.finalize()

class _UniffiFfiConverterOptionalString(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        if value is not None:
            _UniffiFfiConverterString.check_lower(value)

    @classmethod
    def write(cls, value, buf):
        if value is None:
            buf.write_u8(0)
            return

        buf.write_u8(1)
        _UniffiFfiConverterString.write(value, buf)

    @classmethod
    def read(cls, buf):
        flag = buf.read_u8()
        if flag == 0:
            return None
        elif flag == 1:
            return _UniffiFfiConverterString.read(buf)
        else:
            raise InternalError("Unexpected flag byte for optional type")

@dataclass
class Translation:
    def __init__(self, *, lang:str, value:str):
        self.lang = lang
        self.value = value
        
        

    
    def __str__(self):
        return "Translation(lang={}, value={})".format(self.lang, self.value)
    def __eq__(self, other):
        if self.lang != other.lang:
            return False
        if self.value != other.value:
            return False
        return True

class _UniffiFfiConverterTypeTranslation(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        return Translation(
            lang=_UniffiFfiConverterString.read(buf),
            value=_UniffiFfiConverterString.read(buf),
        )

    @staticmethod
    def check_lower(value):
        _UniffiFfiConverterString.check_lower(value.lang)
        _UniffiFfiConverterString.check_lower(value.value)

    @staticmethod
    def write(value, buf):
        _UniffiFfiConverterString.write(value.lang, buf)
        _UniffiFfiConverterString.write(value.value, buf)

class _UniffiFfiConverterSequenceTypeTranslation(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        for item in value:
            _UniffiFfiConverterTypeTranslation.check_lower(item)

    @classmethod
    def write(cls, value, buf):
        items = len(value)
        buf.write_i32(items)
        for item in value:
            _UniffiFfiConverterTypeTranslation.write(item, buf)

    @classmethod
    def read(cls, buf):
        count = buf.read_i32()
        if count < 0:
            raise InternalError("Unexpected negative sequence length")

        return [
            _UniffiFfiConverterTypeTranslation.read(buf) for i in range(count)
        ]

@dataclass
class EnumWrapper:
    def __init__(self, *, name:str, variant:str, value:str):
        self.name = name
        self.variant = variant
        self.value = value
        
        

    
    def __str__(self):
        return "EnumWrapper(name={}, variant={}, value={})".format(self.name, self.variant, self.value)
    def __eq__(self, other):
        if self.name != other.name:
            return False
        if self.variant != other.variant:
            return False
        if self.value != other.value:
            return False
        return True

class _UniffiFfiConverterTypeEnumWrapper(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        return EnumWrapper(
            name=_UniffiFfiConverterString.read(buf),
            variant=_UniffiFfiConverterString.read(buf),
            value=_UniffiFfiConverterString.read(buf),
        )

    @staticmethod
    def check_lower(value):
        _UniffiFfiConverterString.check_lower(value.name)
        _UniffiFfiConverterString.check_lower(value.variant)
        _UniffiFfiConverterString.check_lower(value.value)

    @staticmethod
    def write(value, buf):
        _UniffiFfiConverterString.write(value.name, buf)
        _UniffiFfiConverterString.write(value.variant, buf)
        _UniffiFfiConverterString.write(value.value, buf)

class _UniffiFfiConverterOptionalTypeEnumWrapper(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        if value is not None:
            _UniffiFfiConverterTypeEnumWrapper.check_lower(value)

    @classmethod
    def write(cls, value, buf):
        if value is None:
            buf.write_u8(0)
            return

        buf.write_u8(1)
        _UniffiFfiConverterTypeEnumWrapper.write(value, buf)

    @classmethod
    def read(cls, buf):
        flag = buf.read_u8()
        if flag == 0:
            return None
        elif flag == 1:
            return _UniffiFfiConverterTypeEnumWrapper.read(buf)
        else:
            raise InternalError("Unexpected flag byte for optional type")

