class DefinitionOrGroup:
    def __init__(self):
        raise RuntimeError("DefinitionOrGroup cannot be instantiated directly")

    # Each enum variant is a nested class of the enum itself.
    @dataclass
    class DEFINITION:
        
        def __init__(self, *values):
            if len(values) != 1:
                raise TypeError(f"Expected 1 arguments, found {len(values)}")
            self._values = values

        def __getitem__(self, index):
            return self._values[index]

    
            
            

    
        def __str__(self):
            return f"DefinitionOrGroup.DEFINITION{self._values!r}"
        def __eq__(self, other):
            if not other.is_DEFINITION():
                return False
            return self._values == other._values

    @dataclass
    class GROUP:
        
        def __init__(self, *values):
            if len(values) != 1:
                raise TypeError(f"Expected 1 arguments, found {len(values)}")
            self._values = values

        def __getitem__(self, index):
            return self._values[index]

    
            
            

    
        def __str__(self):
            return f"DefinitionOrGroup.GROUP{self._values!r}"
        def __eq__(self, other):
            if not other.is_GROUP():
                return False
            return self._values == other._values

    

    # For each variant, we have `is_NAME` and `is_name` methods for easily checking
    # whether an instance is that variant.
    def is_DEFINITION(self) -> bool:
        return isinstance(self, DefinitionOrGroup.DEFINITION)
    def is_definition(self) -> bool:
        return isinstance(self, DefinitionOrGroup.DEFINITION)
    def is_GROUP(self) -> bool:
        return isinstance(self, DefinitionOrGroup.GROUP)
    def is_group(self) -> bool:
        return isinstance(self, DefinitionOrGroup.GROUP)
    

# Now, a little trick - we make each nested variant class be a subclass of the main
# enum class, so that method calls and instance checks etc will work intuitively.
# We might be able to do this a little more neatly with a metaclass, but this'll do.
DefinitionOrGroup.DEFINITION = type("DefinitionOrGroup.DEFINITION", (DefinitionOrGroup.DEFINITION, DefinitionOrGroup,), {})  # type: ignore
DefinitionOrGroup.GROUP = type("DefinitionOrGroup.GROUP", (DefinitionOrGroup.GROUP, DefinitionOrGroup,), {})  # type: ignore




class _UniffiFfiConverterTypeDefinitionOrGroup(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return DefinitionOrGroup.DEFINITION(
                _UniffiFfiConverterTypeDefinition.read(buf),
            )
        if variant == 2:
            return DefinitionOrGroup.GROUP(
                _UniffiFfiConverterTypeGroup.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value.is_DEFINITION():
            _UniffiFfiConverterTypeDefinition.check_lower(value._values[0])
            return
        if value.is_GROUP():
            _UniffiFfiConverterTypeGroup.check_lower(value._values[0])
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value.is_DEFINITION():
            buf.write_i32(1)
            _UniffiFfiConverterTypeDefinition.write(value._values[0], buf)
        if value.is_GROUP():
            buf.write_i32(2)
            _UniffiFfiConverterTypeGroup.write(value._values[0], buf)



